import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"天安门广场","description":"","frontmatter":{},"headers":[],"relativePath":"history/tiananmen-square.md","filePath":"history/tiananmen-square.md","lastUpdated":null}'),n={name:"history/tiananmen-square.md"};function o(i,t,s,d,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="天安门广场" tabindex="-1">天安门广场 <a class="header-anchor" href="#天安门广场" aria-label="Permalink to &quot;天安门广场&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=1200" alt="天安门广场"></p><blockquote><p>&quot;世界最大城市广场，祖国的心脏。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>天安门广场位于北京市中心，南北长880米，东西宽500米，面积达44万平方米，是世界上最大的城市广场。广场北依天安门，南接正阳门，东为国家博物馆，西为人民大会堂，中央矗立着人民英雄纪念碑和毛主席纪念堂。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放（需安检）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳时间</strong></td><td style="text-align:left;">升旗/降旗仪式</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东/西站</td></tr><tr><td style="text-align:left;"><strong>注意事项</strong></td><td style="text-align:left;">需携带身份证，安检严格</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="明清时期" tabindex="-1">明清时期 <a class="header-anchor" href="#明清时期" aria-label="Permalink to &quot;明清时期&quot;">​</a></h3><p>明清时期，天安门广场是皇城的正门，称为&quot;天街&quot;，是禁地，普通百姓不得进入。广场呈&quot;T&quot;字形，两侧有千步廊，是朝廷举行重大典礼的地方。</p><h3 id="民国时期" tabindex="-1">民国时期 <a class="header-anchor" href="#民国时期" aria-label="Permalink to &quot;民国时期&quot;">​</a></h3><p>1912年，中华民国成立后，天安门广场开始对外开放。1919年五四运动、1935年一二·九运动等重大历史事件在此发生。</p><h3 id="新中国成立后" tabindex="-1">新中国成立后 <a class="header-anchor" href="#新中国成立后" aria-label="Permalink to &quot;新中国成立后&quot;">​</a></h3><p>1949年10月1日，毛泽东主席在天安门城楼上庄严宣告中华人民共和国成立，天安门广场成为新中国的象征。</p><p>此后，广场进行了多次扩建，形成了今日的规模。</p><h2 id="主要建筑" tabindex="-1">主要建筑 <a class="header-anchor" href="#主要建筑" aria-label="Permalink to &quot;主要建筑&quot;">​</a></h2><h3 id="天安门" tabindex="-1">天安门 <a class="header-anchor" href="#天安门" aria-label="Permalink to &quot;天安门&quot;">​</a></h3><p>天安门始建于明永乐十五年（1417年），原名&quot;承天门&quot;，清顺治八年（1651年）重修后改称&quot;天安门&quot;。天安门是明清两代皇城的正门，也是新中国最重要的象征。</p><h4 id="建筑特点" tabindex="-1">建筑特点 <a class="header-anchor" href="#建筑特点" aria-label="Permalink to &quot;建筑特点&quot;">​</a></h4><ul><li><strong>高度</strong>：约35米</li><li><strong>结构</strong>：重檐歇山顶，黄琉璃瓦</li><li><strong>城门</strong>：五个门洞，中间最大</li><li><strong>匾额</strong>：悬挂毛泽东画像和&quot;中华人民共和国万岁&quot;&quot;世界人民大团结万岁&quot;标语</li></ul><h4 id="毛主席画像" tabindex="-1">毛主席画像 <a class="header-anchor" href="#毛主席画像" aria-label="Permalink to &quot;毛主席画像&quot;">​</a></h4><p>天安门城楼上悬挂的毛泽东画像，高6米，宽4.6米，由著名画家王国栋绘制。画像每年国庆节前更换一幅新像。</p><h3 id="人民英雄纪念碑" tabindex="-1">人民英雄纪念碑 <a class="header-anchor" href="#人民英雄纪念碑" aria-label="Permalink to &quot;人民英雄纪念碑&quot;">​</a></h3><p>人民英雄纪念碑位于天安门广场中央，高37.94米，碑身正面镌刻着毛泽东题写的&quot;人民英雄永垂不朽&quot;八个鎏金大字。</p><p><a href="/beijing-travel-guide/history/monument.html">查看人民英雄纪念碑详情 →</a></p><h3 id="毛主席纪念堂" tabindex="-1">毛主席纪念堂 <a class="header-anchor" href="#毛主席纪念堂" aria-label="Permalink to &quot;毛主席纪念堂&quot;">​</a></h3><p>毛主席纪念堂位于天安门广场南端，是瞻仰毛泽东主席遗容的场所。</p><p><a href="/beijing-travel-guide/history/mausoleum.html">查看毛主席纪念堂详情 →</a></p><h3 id="人民大会堂" tabindex="-1">人民大会堂 <a class="header-anchor" href="#人民大会堂" aria-label="Permalink to &quot;人民大会堂&quot;">​</a></h3><p>人民大会堂位于天安门广场西侧，是全国人民代表大会开会的地方，也是国家举行重大活动的场所。</p><h3 id="中国国家博物馆" tabindex="-1">中国国家博物馆 <a class="header-anchor" href="#中国国家博物馆" aria-label="Permalink to &quot;中国国家博物馆&quot;">​</a></h3><p>中国国家博物馆位于天安门广场东侧，是世界上建筑面积最大的博物馆。</p><p><a href="/beijing-travel-guide/museums/national-museum.html">查看国家博物馆详情 →</a></p><h3 id="正阳门" tabindex="-1">正阳门 <a class="header-anchor" href="#正阳门" aria-label="Permalink to &quot;正阳门&quot;">​</a></h3><p>正阳门位于天安门广场南端，是明清北京内城的正门，也是北京城的标志性建筑。</p><p><a href="/beijing-travel-guide/landmarks/qianmen.html">查看正阳门详情 →</a></p><h2 id="升旗仪式" tabindex="-1">升旗仪式 <a class="header-anchor" href="#升旗仪式" aria-label="Permalink to &quot;升旗仪式&quot;">​</a></h2><p>天安门广场的升旗仪式是必看的项目。</p><h3 id="升旗时间" tabindex="-1">升旗时间 <a class="header-anchor" href="#升旗时间" aria-label="Permalink to &quot;升旗时间&quot;">​</a></h3><p>升旗时间与日出同步，每天不同。夏季约5:00左右，冬季约7:00左右。</p><h3 id="观看位置" tabindex="-1">观看位置 <a class="header-anchor" href="#观看位置" aria-label="Permalink to &quot;观看位置&quot;">​</a></h3><ul><li><strong>最佳位置</strong>：旗杆正前方，需提前到达占位</li><li><strong>侧面位置</strong>：人较少，但观看角度偏</li></ul><h3 id="观看建议" tabindex="-1">观看建议 <a class="header-anchor" href="#观看建议" aria-label="Permalink to &quot;观看建议&quot;">​</a></h3><ol><li><strong>提前到达</strong>：节假日需提前2-3小时到达</li><li><strong>携带证件</strong>：需刷身份证入场</li><li><strong>安检严格</strong>：禁止携带违禁品</li><li><strong>注意保暖</strong>：清晨较冷，注意保暖</li><li><strong>降旗仪式</strong>：如赶不上升旗，可看降旗</li></ol><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2小时）</strong>：</p><p>观看升旗 → 参观广场 → 人民英雄纪念碑 → 毛主席纪念堂（如需参观） → 国家博物馆（如需参观）</p><p><strong>结合故宫路线（约1天）</strong>：</p><p>观看升旗 → 天安门广场 → 故宫博物院 → 景山公园</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线天安门东站或西站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、2路、52路等天安门站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从前门大街步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>安检严格</strong>：必须携带身份证，安检严格</li><li><strong>禁止携带</strong>：打火机、刀具等违禁品</li><li><strong>存包服务</strong>：大包需寄存</li><li><strong>穿着得体</strong>：毛主席纪念堂需穿长裤，不得穿拖鞋</li><li><strong>注意时间</strong>：升旗时间每天不同，提前查询</li><li><strong>避开高峰</strong>：节假日人极多，建议工作日前往</li></ol><h2 id="历史事件" tabindex="-1">历史事件 <a class="header-anchor" href="#历史事件" aria-label="Permalink to &quot;历史事件&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">时间</th><th style="text-align:left;">事件</th><th style="text-align:left;">意义</th></tr></thead><tbody><tr><td style="text-align:center;">1919年5月4日</td><td style="text-align:left;">五四运动</td><td style="text-align:left;">新民主主义革命开端</td></tr><tr><td style="text-align:center;">1935年12月9日</td><td style="text-align:left;">一二·九运动</td><td style="text-align:left;">抗日救亡运动高潮</td></tr><tr><td style="text-align:center;">1949年10月1日</td><td style="text-align:left;">开国大典</td><td style="text-align:left;">中华人民共和国成立</td></tr><tr><td style="text-align:center;">1976年4月5日</td><td style="text-align:left;">四五运动</td><td style="text-align:left;">悼念周总理</td></tr><tr><td style="text-align:center;">1989年</td><td style="text-align:left;">六四事件</td><td style="text-align:left;">-</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>天安门广场是中国的政治象征，是国家举行重大庆典和集会的场所。</p><p>1949年10月1日，毛泽东主席在天安门城楼上庄严宣告中华人民共和国成立，从此&quot;中国人民站起来了&quot;。这一历史时刻被永远铭刻在人民英雄纪念碑的浮雕上。</p><p>天安门广场见证了新中国的诞生和发展，是中国人民心中的圣地。</p><hr><p><strong>📍 地址</strong>：北京市东城区天安门广场 <strong>🚇 地铁</strong>：1号线天安门东站或西站</p>',62)])])}const c=a(n,[["render",o]]);export{q as __pageData,c as default};
